class Stack {
    private int[] arr;
    private int top;
    private int capacity;

    public Stack(int size) {
        arr = new int[size];
        capacity = size;
        top = -1;
    }

    public void push(int x) {
        if (top == capacity - 1) {
            System.out.println("栈满");
            return;
        }
        arr[++top] = x;
    }

    public int pop() {
        if (top == -1) {
            System.out.println("栈空");
            return -1;
        }
        return arr[top--];
    }

    public int peek() {
        if (top == -1) {
            return -1;
        }
        return arr[top];
    }
}

public class Main {
    public static void main(String[] args) {
        Stack stack = new Stack(5);
        stack.push(10);
        stack.push(20);
        stack.push(30);

        System.out.println("栈顶元素: " + stack.peek());
        System.out.println("弹出: " + stack.pop());
        System.out.println("弹出后栈顶: " + stack.peek());
    }
}

class Stack:
    def __init__(self, size):
        self.arr = []
        self.capacity = size

    def push(self, x):
        if len(self.arr) >= self.capacity:
            print("栈满")
            return
        self.arr.append(x)

    def pop(self):
        if not self.arr:
            print("栈空")
            return -1
        return self.arr.pop()

    def peek(self):
        if not self.arr:
            return -1
        return self.arr[-1]

